//
//     final package = packageFromJson(jsonString);

import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    Repository repository;
    String license;
    String description;
    List<String> keywords;
    String version;

    Package({
        required this.name,
        required this.repository,
        required this.license,
        required this.description,
        required this.keywords,
        required this.version,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        repository: Repository.fromJson(json["repository"]),
        license: json["license"],
        description: json["description"],
        keywords: List<String>.from(json["keywords"].map((x) => x)),
        version: json["version"],
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "repository": repository.toJson(),
        "license": license,
        "description": description,
        "keywords": List<dynamic>.from(keywords.map((x) => x)),
        "version": version,
    };
}

class Repository {
    String type;
    String url;
    String directory;

    Repository({
        required this.type,
        required this.url,
        required this.directory,
    });

    factory Repository.fromJson(Map<String, dynamic> json) => Repository(
        type: json["type"],
        url: json["url"],
        directory: json["directory"],
    );

    Map<String, dynamic> toJson() => {
        "type": type,
        "url": url,
        "directory": directory,
    };
}
